VALUES
  ('locality-6f0ba476-moex-00005', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'essay', '甲騎乘電動滑板車沿〇〇路東側人行道北向南行駛（非縣市政府指定之
行駛路段）至肇事路口時，見東西向行人燈小綠人閃爍，遂直接右轉上
行人穿越道欲快速通過道路，惟正當甲眼光放在行人燈時，甲迎面撞上
行走在行人穿越道上的乙行人，乙行人跌倒後頭部撞及地面，送醫後治
療醫師乃判定其腦部重度損傷。試問：甲之行為依民法應對乙負何種責
任？若乙受監護宣告，並選定乙之女丙為監護人，丙欲將乙接至桃園住
處照顧，但乙之子丁為乙就醫方便則留乙在臺中，且細心協助就醫，丙
只好奔波於二地，則丙得否以監護人之「居住所指定權」及「交還請求
權」受侵害主張交通費用9,000元的損害賠償？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00006', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '依民法規定，有關法律文書中文字與數字之使用，下列敘述何者正確？', '["若應簽名者不識字，可由他人代為簽名。只要當場有二人簽名證明，亦與簽名生同等之效力", "僅按捺指印不可以代替簽名", "同時以文字與號碼表示一定之數量，但兩者不符合時，視為以文字為準", "有使用文字必要之要式行為，不得經由他人代筆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00007', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲將自有A地出租於乙，租期1年，月租金新臺幣（下同）5萬元，乙應每月15日匯入甲在B 銀行帳戶。今年2月底，甲將A地售讓於丙，並於3月1日完成移轉所有權登記。丙並將受讓 A地所有權之情事通知乙，惟至今，乙仍每月將A地租金匯入甲在B銀行帳戶。下列敘述何者 正確？', '["甲仍得基於A地租賃契約，繼續向乙請求支付並取得租金", "該租賃契約因A地移轉而失效", "丙得向乙請求給付相當於租金之不當得利", "丙得向乙請求支付3月1日起，每月5萬元租金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00008', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於消滅時效中斷之敘述，何者正確？', '["消滅時效中斷，乃是於時效將完成時，為避免債務人不清償，而允許時效期間接續延長", "時效，因承認而中斷者，若於承認後6個月內不起訴，視為不中斷", "時效，因起訴而中斷者，若撤回其訴，或因不合法而受駁回之裁判，其裁判確定，視為不中斷", "因起訴而中斷之時效，自受確定判決，或因其他方法訴訟終結時，重行起算之時效期間，均為 5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00009', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '試驗買賣契約之性質為何？', '["附停止條件之契約", "附解除條件之契約", "附始期之契約", "附終期之契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00010', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於期日及期間之敘述，何者錯誤？', '["休息日在期間中而非期間之末日者，不得予以扣除", "民法第120條關於始日不算入之規定，於年齡之計算，即不得適用", "於計算年齡之末日，為星期日、紀念日或其他休息日時，得適用民法第122條有關期日補充與 期間延長之規定", "死亡之月、日無從確定時，得類推適用民法第124條有關年齡計算之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00011', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '丙受僱於甲遊覽公司，擔任旅行團之司機。某日，於載送觀光團前往著名景點旅途中，因分心且 車速過快，致車輛失控而翻落山谷，導致車上之乘客乙受傷，並支出醫療費用新臺幣10萬元， 下列敘述何者錯誤？', '["丙為甲公司之司機，為甲公司之機關，乙得依民法第28條有關法人侵權行為之規定，向甲公 司請求損害賠償", "丙受僱於甲公司，其於執行職務之際，因過失致乙之身體權受侵害，丙之行為構成民法第184 條第1項前段之侵權行為，丙應就其行為負損害賠償責任", "若甲公司能舉證其選任丙及監督丙職務之執行已盡相當注意，其得主張不負賠償責任", "甲公司為丙之僱用人，應依民法第188條第1項有關受僱人與僱用人侵權行為之規定，與丙就 乙之損害，負連帶賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00012', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲向乙承租店面A，供經營餐廳使用。某日，甲之受僱人丙於添加菜餚加熱用之酒精膏時，不慎 引發大火燒毀A屋並燒傷顧客丁。關於當事人間之法律關係，下列敘述何者正確？', '["丙不具重大過失時，丁不得向甲主張民法第188條有關受僱人之侵權行為責任", "丙不具重大過失時，乙不得向甲主張民法第434條有關租賃物之失火責任", "丙不具重大過失時，丁不得向丙主張民法第184條第1項前段規定之侵權行為責任", "丙不具重大過失時，乙不得向丙主張民法第184條第1項前段規定之侵權行為責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00013', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲有感於自己時日無多，遂有意將自己所有價值不斐之A車及B畫分別贈與其長孫乙及友人丙。 下列關於贈與契約之敘述，何者正確？', '["贈與對受贈人來說，係純獲法律上利益，所以即使丙認為自己無功不受祿而予以婉拒，贈與契 約仍生效", "贈與契約是要物契約，故在交付A車前，甲得主張贈與契約不生效力", "甲不知A車煞車有問題而將其交付於乙，嗣後乙駕車時，因A車煞車失靈，致發生車禍骨折， 乙得向甲主張另行交付無瑕疵之同款汽車", "乙得知其獲甲贈與A車，怕甲反悔遂經公證。公證後，乙始與丁訂立停車位租賃契約，但甲遲 遲不交付A車，乙卻已經開始支付丁租金，則乙於贈與契約成立生效後，得請求甲交付A車"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00014', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲與乙訂立預售屋買賣契約，向乙購買預售屋，雙方約定甲有按期先給付價金之義務，但乙於訂 約後發生財務危機，財產顯形減少，致有無法續建房屋之虞。下列敘述何者正確？', '["甲得主張不安抗辯", "甲得主張惡意抗辯", "甲得主張同時履行抗辯", "甲得主張消滅時效抗辯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
